from flask import Flask, redirect, url_for, session, request
from flask_oidc import OpenIDConnect
from urllib.parse import parse_qs

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your_secret_key'
app.config['OIDC_CLIENT_SECRETS'] = 'client_secrets.json'
app.config['OIDC_ID_TOKEN_COOKIE_SECURE'] = False  # for development only
app.config['OIDC_SCOPES'] = ['openid', 'email']
oidc = OpenIDConnect(app)

@app.route('/')
def index():
    return redirect(url_for('login'))

@app.route('/login')
@oidc.require_login
def login():
    return 'You are logged in!'

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

@app.route('/oidc_callback')
@oidc.authorized_handler
def authorized_callback():
    if 'error' in request.args:
        return request.args['error'] + ': ' + request.args.get('error_description', '')
    resp = oidc.callback()
    if resp is None:
        return redirect(url_for('index'))
    session['user_id'] = resp.user_id
    session['username'] = resp.username
    session['email'] = resp.email
    return redirect(url_for('login'))

if __name__ == '__main__':
    app.run(debug=True)